// 实现元数据提取脚本插件
// 该脚本会提取所有数据表和字段的信息，并将其存储在指定的元数据表中

async function main() {
  try {
    // 使用表单方式获取用户输入配置
    const formResult = await Input.formAsync('元数据提取配置', [
      {
        type: 'sheet',
        key: 'metadataTable',
        option: {
          label: '元数据表',
          description: '请选择用于存储元数据的数据表（默认为当前激活的数据表）'
        },
        required: false
      },
      {
        type: 'field',
        key: 'tableIdField',
        option: {
          label: '表ID字段',
          description: '请选择用于存储表ID的字段（默认为"表ID"）',
          referenceSheet: 'metadataTable'
        },
        required: false
      },
      {
        type: 'field',
        key: 'tableNameField',
        option: {
          label: '表名称字段',
          description: '请选择用于存储表名称的字段（默认为"表名称"）',
          referenceSheet: 'metadataTable'
        },
        required: false
      },
      {
        type: 'field',
        key: 'fieldIdField',
        option: {
          label: '字段ID字段',
          description: '请选择用于存储字段ID的字段（默认为"字段ID"）',
          referenceSheet: 'metadataTable'
        },
        required: false
      },
      {
        type: 'field',
        key: 'fieldNameField',
        option: {
          label: '字段名称字段',
          description: '请选择用于存储字段名称的字段（默认为"字段名称"）',
          referenceSheet: 'metadataTable'
        },
        required: false
      },
      {
        type: 'field',
        key: 'fieldDescriptionField',
        option: {
          label: '字段描述字段',
          description: '请选择用于存储字段描述的字段（默认为"字段描述"）',
          referenceSheet: 'metadataTable'
        },
        required: false
      },
      {
        type: 'field',
        key: 'fieldTypeField',
        option: {
          label: '字段类型字段',
          description: '请选择用于存储字段类型的字段（默认为"字段类型"）',
          referenceSheet: 'metadataTable'
        },
        required: false
      },
      {
        type: 'field',
        key: 'fieldOptionsField',
        option: {
          label: '字段选项字段',
          description: '请选择用于存储字段选项的字段（默认为"字段选项"）',
          referenceSheet: 'metadataTable'
        },
        required: false
      }
    ]);

    // 获取元数据表和字段
    let metadataTable = formResult.metadataTable;
    // 如果没有选择元数据表，使用当前激活的数据表
    if (!metadataTable) {
      metadataTable = Base.getActiveSheet();
      if (!metadataTable) {
        Output.error('请先激活一个数据表或选择元数据表');
        return;
      }
    }

    // 获取字段名称，如果未选择则使用默认值
    const tableIdFieldName = formResult.tableIdField ? formResult.tableIdField.getName() : '表ID';
    const tableNameFieldName = formResult.tableNameField ? formResult.tableNameField.getName() : '表名称';
    const fieldIdFieldName = formResult.fieldIdField ? formResult.fieldIdField.getName() : '字段ID';
    const fieldNameFieldName = formResult.fieldNameField ? formResult.fieldNameField.getName() : '字段名称';
    const fieldDescriptionFieldName = formResult.fieldDescriptionField ? formResult.fieldDescriptionField.getName() : '字段描述';
    const fieldTypeFieldName = formResult.fieldTypeField ? formResult.fieldTypeField.getName() : '字段类型';
    const fieldOptionsFieldName = formResult.fieldOptionsField ? formResult.fieldOptionsField.getName() : '字段选项';

    // 验证元数据表中的字段是否存在，如果不存在则创建
    let tableIdField = metadataTable.getField(tableIdFieldName);
    let tableNameField = metadataTable.getField(tableNameFieldName);
    let fieldIdField = metadataTable.getField(fieldIdFieldName);
    let fieldNameField = metadataTable.getField(fieldNameFieldName);
    let fieldDescriptionField = metadataTable.getField(fieldDescriptionFieldName);
    let fieldTypeField = metadataTable.getField(fieldTypeFieldName);
    let fieldOptionsField = metadataTable.getField(fieldOptionsFieldName);

    // 如果字段不存在，创建它们
    if (!tableIdField) {
      tableIdField = metadataTable.insertField({ name: tableIdFieldName, type: 'text' });
    }
    if (!tableNameField) {
      tableNameField = metadataTable.insertField({ name: tableNameFieldName, type: 'text' });
    }
    if (!fieldIdField) {
      fieldIdField = metadataTable.insertField({ name: fieldIdFieldName, type: 'text' });
    }
    if (!fieldNameField) {
      fieldNameField = metadataTable.insertField({ name: fieldNameFieldName, type: 'text' });
    }
    if (!fieldDescriptionField) {
      fieldDescriptionField = metadataTable.insertField({ name: fieldDescriptionFieldName, type: 'text' });
    }
    if (!fieldTypeField) {
      fieldTypeField = metadataTable.insertField({ name: fieldTypeFieldName, type: 'text' });
    }
    if (!fieldOptionsField) {
      fieldOptionsField = metadataTable.insertField({ name: fieldOptionsFieldName, type: 'text' });
    }

    // 构建记录键的函数
    function buildRecordKey(tableId, fieldId) {
      return `${tableId}-${fieldId}`;
    }

    // 获取字段选项的函数
    function getFieldOptions(field) {
      // 注意：由于API限制，我们可能无法获取所有字段类型的选项信息
      // 这里提供一个简化版本的实现
      try {
        if (field.getType() === 'singleSelect' || field.getType() === 'multipleSelect') {
          const options = field.getOptions();
          return options.map(option => option.name).join(', ');
        }
        // 其他字段类型暂时不处理选项
        return null;
      } catch (error) {
        // 如果获取选项失败，返回null
        return null;
      }
    }

    // 获取元数据表中现有的记录
    const result = await metadataTable.getRecordsAsync();
    const existingMap = {};

    for (const record of result.records) {
      const tableId = record.getCellValue(tableIdFieldName);
      const fieldId = record.getCellValue(fieldIdFieldName);
      if (tableId && fieldId) {
        const key = buildRecordKey(tableId, fieldId);
        existingMap[key] = record.getId();
      }
    }

    // 获取所有数据表（除了元数据表）
    const allSheets = Base.getSheets();
    const tables = allSheets.filter(sheet => sheet.getId() !== metadataTable.getId());

    // 创建两个数组来存储需要更新和创建的记录
    const updates = [];
    const creates = [];

    // 遍历每个数据表和字段
    for (const table of tables) {
      const fields = table.getFields();
      for (const field of fields) {
        const key = buildRecordKey(table.getId(), field.getId());

        const payload = {
          fields: {
            [tableIdFieldName]: table.getId(),
            [tableNameFieldName]: table.getName(),
            [fieldIdFieldName]: field.getId(),
            [fieldNameFieldName]: field.getName(),
            [fieldDescriptionFieldName]: field.getDescription ? field.getDescription() : null,
            [fieldTypeFieldName]: field.getType(),
            [fieldOptionsFieldName]: getFieldOptions(field),
          }
        };

        if (existingMap[key] !== undefined) {
          // 更新现有记录
          updates.push({
            id: existingMap[key],
            ...payload
          });
        } else {
          // 创建新记录
          creates.push(payload);
        }
      }
    }

    // 写入数据
    Output.log(`需要更新 ${updates.length} 条记录`);
    const maxRecordsPerCall = 50;

    // 更新记录
    while (updates.length > 0) {
      const batch = updates.slice(0, maxRecordsPerCall);
      await metadataTable.updateRecordsAsync(batch);
      updates.splice(0, maxRecordsPerCall);
    }

    Output.log(`需要创建 ${creates.length} 条记录`);

    // 创建记录
    while (creates.length > 0) {
      const batch = creates.slice(0, maxRecordsPerCall);
      await metadataTable.insertRecordsAsync(batch);
      creates.splice(0, maxRecordsPerCall);
    }

    Output.log('元数据提取完成');
  } catch (error) {
    if (error instanceof Error) {
      Output.error(`执行过程中发生错误: ${error.message}`);
    } else {
      Output.error(`执行过程中发生未知错误`);
    }
  }
}

await main();
